INSERT INTO library (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('python', 1, 'beginner', 1, '变量定义与赋值', '["变量","赋值"]', '学习如何定义变量并赋值。', '变量是存储数据的容器。在Python中，使用等号=进行赋值。\n例如，variable_name = value。变量在首次赋值时创建。', '["x = 10\\nprint(x)"]', '["10"]'),
('python', 2, 'beginner', 1, '变量命名规则', '["变量","命名"]', '了解Python变量的命名约定和规则。', '变量名必须以字母或下划线开头，只能包含字母、数字和下划线。\n区分大小写，且不能使用Python关键字作为变量名。', '["my_var = 1\\nprint(my_var)"]', '["1"]'),
('python', 3, 'beginner', 1, '整数数据类型', '["数据类型","整数"]', '学习Python中的整数类型及其操作。', '整数是没有小数部分的数字，可以是正数、负数或零。\n支持加、减、乘、除等算术运算。', '["a = 5\\nb = 3\\nprint(a + b)"]', '["8"]'),
('python', 4, 'beginner', 1, '浮点数数据类型', '["数据类型","浮点数"]', '学习Python中的浮点数类型。', '浮点数是带有小数点的数字，用于表示实数。\n注意浮点数可能有精度误差。', '["x = 3.14\\ny = 2.0\\nprint(x * y)"]', '["6.28"]'),
('python', 5, 'beginner', 1, '字符串数据类型', '["数据类型","字符串"]', '学习Python中的字符串及其基本操作。', '字符串是由字符组成的序列，用单引号或双引号括起来。\n支持拼接、索引和切片操作。', '["s = \\"Hello\\"\\nprint(s)"]', '["Hello"]'),
('python', 6, 'beginner', 1, '布尔数据类型', '["数据类型","布尔"]', '学习Python中的布尔类型及其值。', '布尔类型只有两个值：True和False。\n用于逻辑运算和条件判断。', '["a = True\\nb = False\\nprint(a and b)"]', '["False"]'),
('python', 7, 'beginner', 1, '列表数据类型', '["数据类型","列表"]', '学习Python中的列表及其基本操作。', '列表是有序的可变序列，用方括号定义。\n可以包含不同类型的元素。', '["my_list = [1, 2, 3]\\nprint(my_list)"]', '["[1, 2, 3]"]'),
('python', 8, 'beginner', 1, '元组数据类型', '["数据类型","元组"]', '学习Python中的元组类型。', '元组是有序的不可变序列，用圆括号定义。\n一旦创建，不能修改。', '["my_tuple = (1, 2, 3)\\nprint(my_tuple)"]', '["(1, 2, 3]"]'),
('python', 9, 'beginner', 1, '字典数据类型', '["数据类型","字典"]', '学习Python中的字典类型。', '字典是键值对的集合，用花括号定义。\n键必须是不可变类型。', '["my_dict = {\\"name\\": \\"Alice\\", \\"age\\": 25}\\nprint(my_dict[\\"name\\"])"]', '["Alice"]'),
('python', 10, 'beginner', 1, '集合数据类型', '["数据类型","集合"]', '学习Python中的集合类型。', '集合是无序的唯一元素集合，用花括号或set()定义。\n支持集合运算。', '["my_set = {1, 2, 3}\\nprint(my_set)"]', '["{1, 2, 3}"]'),
('python', 11, 'beginner', 1, '类型转换', '["变量","数据类型","转换"]', '学习如何在不同的数据类型之间转换。', '使用内置函数如int(), float(), str()等进行类型转换。\n例如，将字符串转换为整数。', '["s = \\"123\\"\\nn = int(s)\\nprint(n)"]', '["123"]'),
('python', 12, 'beginner', 1, '多重赋值', '["变量","赋值"]', '学习如何同时为多个变量赋值。', '在Python中，可以使用逗号分隔一次为多个变量赋值。\n例如，a, b = 1, 2。', '["a, b = 1, 2\\nprint(a)\\nprint(b)"]', '["1","2"]'),
('python', 13, 'beginner', 1, '常量约定', '["变量","常量"]', '了解Python中常量的命名约定。', 'Python没有内置常量类型，但约定使用全大写字母表示常量。\n例如，PI = 3.14159。', '["PI = 3.14159\\nprint(PI)"]', '["3.14159"]'),
('python', 14, 'beginner', 1, '查看数据类型', '["变量","数据类型","type"]', '学习如何使用type()函数查看变量的数据类型。', 'type()函数返回对象的数据类型。\n例如，type(5)返回整数类型。', '["x = 5\\nprint(type(x))"]', '["<class ''int''>"]'),
('python', 15, 'beginner', 1, '数据类型总结', '["变量","数据类型"]', '回顾Python中的主要数据类型。', 'Python有几种内置数据类型：整数、浮点数、字符串、布尔值、列表、元组、字典、集合等。\n每种类型有其特性和用途。', '["a = 1\\nb = 3.14\\nc = \\"hello\\"\\nprint(type(a), type(b), type(c))"]', '["<class ''int''> <class ''float''> <class ''str''>"]');